#include <bits/stdc++.h>
using namespace std;
struct Number{
	int len,val[10004];
	void Set(int x){
		int tmp=x;
		len=0;
		while(tmp)
			val[++len]=tmp%10,tmp/=10;
	}
	Number operator*(Number &t){
		Number tmp;
		memset(tmp.val,0,sizeof(tmp.val));
		tmp.len=len+t.len-1;
		for(int i=1;i<=len;i++)
			for(int j=1;j<=t.len;j++)
				tmp.val[i+j-1]+=val[i]*t.val[j],tmp.val[i+j]+=tmp.val[i+j-1]/10,tmp.val[i+j-1]%=10;
		while(tmp.val[tmp.len+1])
			tmp.len++,tmp.val[tmp.len+1]+=tmp.val[tmp.len]/10,tmp.val[tmp.len]%=10;
		return tmp;
	}
};
void output(Number num){
	for(int i=num.len;i;i--)
		printf("%d",num.val[i]);
	printf("\n");
}
int n;
Number quick_mi(int a,int b){
	Number ans,base;
	ans.Set(1),base.Set(a);
	while(b){
		if(b&1)
			ans=ans*base;
		base=base*base,b>>=1;
	}
	return ans;
}
int main(){
	scanf("%d",&n);
	Number tmp=quick_mi(2,n+1);
	tmp.val[1]-=2;
	output(tmp);
	return 0;
}
